contracts/interfaces/IVaultVerifier.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/// @title IVaultVerifier
/// @notice Interface for cross-chain NFT ownership verification on Monad.
/// @dev Two implementations exist: OracleVerifier (oracle-backed, Phase 1)
///      and ZKVerifier (Solana light client, Phase 3+).
interface IVaultVerifier {
    /// @notice Emitted when a verification succeeds.
    /// @param nftMint  The Solana NFT mint address (base58 as bytes32).
    /// @param owner    The Solana wallet address claiming ownership.
    /// @param expiry   Unix timestamp after which this proof is invalid.
    event OwnershipVerified(
        bytes32 indexed nftMint,
        bytes32 indexed owner,
        uint256 expiry
    );

    /// @notice Emitted when an oracle signer is added or removed.
    event SignerUpdated(address indexed signer, bool approved);

    /// @notice Verify that `owner` holds the Solana NFT identified by `nftMint`.
    /// @dev    Reverts if proof is invalid, expired, or the verifier is paused.
    /// @param nftMint  The Solana NFT mint address encoded as bytes32.
    /// @param owner    The Solana wallet address encoded as bytes32.
    /// @param proof    Verifier-specific proof payload (oracle sig or Merkle proof).
    /// @param expiry   Unix timestamp — proof must not be used after this time.
    /// @return valid   True if ownership is confirmed.
    function verifyOwnership(
        bytes32 nftMint,
        bytes32 owner,
        bytes calldata proof,
        uint256 expiry
    ) external returns (bool valid);

    /// @notice Returns the last verified owner for a given NFT mint.
    /// @dev    Returns zero bytes if the NFT has never been verified.
    function lastVerifiedOwner(bytes32 nftMint) external view returns (bytes32 owner);

    /// @notice Returns the block timestamp when the last verification for
    ///         `nftMint` was recorded.
    function lastVerifiedAt(bytes32 nftMint) external view returns (uint256 timestamp);

    /// @notice True if the verifier is accepting new proof submissions.
    function isActive() external view returns (bool);
}

contracts/verifiers/OracleVerifier.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "../interfaces/IVaultVerifier.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";
import "@openzeppelin/contracts/utils/cryptography/MessageHashUtils.sol";

/// @title OracleVerifier
/// @notice Phase 1 vault verifier — trusts a set of approved oracle signers
///         to attest Solana NFT ownership on-chain on Monad.
///
/// @dev The oracle produces an off-chain ECDSA signature over:
///      keccak256(abi.encodePacked(nftMint, owner, expiry, block.chainid))
///
///      The Locker contract calls verifyOwnership() before allowing any
///      vault action that requires confirmed NFT custody.
///
///      This contract is intentionally simple — it will be replaced by
///      ZKVerifier once the Solana light client is production-ready.
contract OracleVerifier is IVaultVerifier, Ownable, Pausable {
    using ECDSA for bytes32;
    using MessageHashUtils for bytes32;

    /// @notice Approved oracle signers.
    mapping(address => bool) public approvedSigners;

    /// @notice Most recent verified owner per NFT mint.
    mapping(bytes32 => bytes32) private _lastOwner;

    /// @notice Timestamp of the most recent successful verification per mint.
    mapping(bytes32 => uint256) private _lastVerifiedAt;

    /// @notice Proofs that have already been consumed (replay protection).
    mapping(bytes32 => bool) private _usedProofs;

    /// @notice Maximum allowed proof age in seconds (default 5 minutes).
    uint256 public maxProofAge = 5 minutes;

    constructor(address initialOwner, address initialSigner)
        Ownable(initialOwner)
    {
        _setSigner(initialSigner, true);
    }

    /// @inheritdoc IVaultVerifier
    function verifyOwnership(
        bytes32 nftMint,
        bytes32 owner,
        bytes calldata proof,
        uint256 expiry
    ) external override whenNotPaused returns (bool valid) {
        require(block.timestamp <= expiry, "OracleVerifier: proof expired");
        require(
            expiry <= block.timestamp + maxProofAge,
            "OracleVerifier: proof expiry too far in future"
        );

        // Proof is a raw 65-byte ECDSA signature.
        require(proof.length == 65, "OracleVerifier: invalid proof length");

        // Reconstruct the signed digest.
        bytes32 digest = keccak256(
            abi.encodePacked(nftMint, owner, expiry, block.chainid)
        ).toEthSignedMessageHash();

        // Replay guard — each (digest) can only be used once.
        require(!_usedProofs[digest], "OracleVerifier: proof already used");

        address recovered = digest.recover(proof);
        require(approvedSigners[recovered], "OracleVerifier: signer not approved");

        // Mark proof consumed.
        _usedProofs[digest] = true;

        // Record result.
        _lastOwner[nftMint] = owner;
        _lastVerifiedAt[nftMint] = block.timestamp;

        emit OwnershipVerified(nftMint, owner, expiry);
        return true;
    }

    /// @inheritdoc IVaultVerifier
    function lastVerifiedOwner(bytes32 nftMint) external view override returns (bytes32) {
        return _lastOwner[nftMint];
    }

    /// @inheritdoc IVaultVerifier
    function lastVerifiedAt(bytes32 nftMint) external view override returns (uint256) {
        return _lastVerifiedAt[nftMint];
    }

    /// @inheritdoc IVaultVerifier
    function isActive() external view override returns (bool) {
        return !paused();
    }

    // ─── Admin ───────────────────────────────────────────────────────────────

    /// @notice Add or remove an approved oracle signer.
    function setSigner(address signer, bool approved) external onlyOwner {
        _setSigner(signer, approved);
    }

    /// @notice Update the maximum allowed proof age.
    function setMaxProofAge(uint256 newAge) external onlyOwner {
        require(newAge >= 60 && newAge <= 1 hours, "OracleVerifier: age out of range");
        maxProofAge = newAge;
    }

    /// @notice Pause the verifier — no proofs accepted while paused.
    function pause() external onlyOwner {
        _pause();
    }

    /// @notice Resume accepting proofs.
    function unpause() external onlyOwner {
        _unpause();
    }

    // ─── Internal ────────────────────────────────────────────────────────────

    function _setSigner(address signer, bool approved) internal {
        require(signer != address(0), "OracleVerifier: zero address");
        approvedSigners[signer] = approved;
        emit SignerUpdated(signer, approved);
    }
}

contracts/verifiers/ZKVerifier.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "../interfaces/IVaultVerifier.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/// @title ZKVerifier
/// @notice Phase 3+ verifier stub — Solana light client running natively on Monad.
///
/// @dev STATUS: STUB — NOT PRODUCTION READY.
///
///      This contract defines the interface and storage layout that the
///      Solana light client verifier will implement. It is deployed on
///      Monad testnet as a placeholder so that Locker contracts can
///      reference the correct address from day one.
///
///      The Solana light client will:
///        1. Maintain a rolling set of verified Solana block headers.
///        2. Accept Merkle proofs of NFT account state from those headers.
///        3. Verify NFT ownership without any trusted intermediary.
///
///      Implementation timeline: 6–12 months of specialist engineering.
///      Formal specification and independent security audit required
///      before any mainnet deployment.
///
///      Until then, MonaSol Protocol uses OracleVerifier for Phase 1.
contract ZKVerifier is IVaultVerifier, Ownable {

    // ─── Light Client State (populated once implementation is ready) ──────────

    /// @notice The most recently accepted Solana slot number.
    uint64 public latestSlot;

    /// @notice Merkle root of the Solana account state at `latestSlot`.
    bytes32 public latestStateRoot;

    /// @notice Mapping from accepted slot → state root (historical window).
    mapping(uint64 => bytes32) public slotRoots;

    // ─── Verification Records ─────────────────────────────────────────────────

    mapping(bytes32 => bytes32) private _lastOwner;
    mapping(bytes32 => uint256) private _lastVerifiedAt;

    bool private _active;

    constructor(address initialOwner) Ownable(initialOwner) {
        _active = false;
    }

    // ─── IVaultVerifier ───────────────────────────────────────────────────────

    /// @inheritdoc IVaultVerifier
    /// @dev STUB: always reverts until the light client is implemented.
    ///      proof is expected to be an RLP-encoded Merkle inclusion proof
    ///      against `latestStateRoot` once real implementation lands.
    function verifyOwnership(
        bytes32,
        bytes32,
        bytes calldata,
        uint256
    ) external override returns (bool) {
        revert("ZKVerifier: not yet implemented - use OracleVerifier");
    }

    /// @inheritdoc IVaultVerifier
    function lastVerifiedOwner(bytes32 nftMint) external view override returns (bytes32) {
        return _lastOwner[nftMint];
    }

    /// @inheritdoc IVaultVerifier
    function lastVerifiedAt(bytes32 nftMint) external view override returns (uint256) {
        return _lastVerifiedAt[nftMint];
    }

    /// @inheritdoc IVaultVerifier
    function isActive() external view override returns (bool) {
        return _active;
    }

    // ─── Admin (light client header relay — placeholder) ─────────────────────

    /// @notice Submit a new Solana slot header.
    /// @dev    In production this will require a validity proof (SNARK/STARK)
    ///         confirming the header is part of the canonical Solana chain.
    ///         For now it is owner-gated as a trusted relay stub.
    function submitHeader(uint64 slot, bytes32 stateRoot) external onlyOwner {
        require(slot > latestSlot, "ZKVerifier: slot not newer");
        latestSlot = slot;
        latestStateRoot = stateRoot;
        slotRoots[slot] = stateRoot;
    }

    /// @notice Activate or deactivate the verifier.
    /// @dev    Will be called once the real implementation passes audit.
    function setActive(bool active) external onlyOwner {
        _active = active;
    }
}

